#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        double celsius;
        if (scanf("%lf", &celsius) != 1) break;
        if (celsius < -273.15) {
            printf("Invalid Argument: Temperature below absolute zero is not valid.\n");
        } else {
            double fahrenheit = (celsius * 9.0 / 5.0) + 32.0;
            printf("Temperature in Celsius: %.2f\n", celsius);
            printf("Temperature in Fahrenheit: %.2f\n", fahrenheit);
        }
    }
    return 0;
}

