import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String s = br.readLine();
            if (s == null) break;
            double celsius = Double.parseDouble(s.trim());
            if (celsius < -273.15) {
                sb.append("Invalid Argument: Temperature below absolute zero is not valid.").append('\n');
            } else {
                double fahrenheit = (celsius * 9.0 / 5.0) + 32.0;
                sb.append(String.format(Locale.US, "Temperature in Celsius: %.2f\n", celsius));
                sb.append(String.format(Locale.US, "Temperature in Fahrenheit: %.2f\n", fahrenheit));
            }
        }
        System.out.print(sb.toString());
    }
}

