import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T + 1):
        celsius = float(data[i].strip())
        if celsius < -273.15:
            out_lines.append("Invalid Argument: Temperature below absolute zero is not valid.")
        else:
            fahrenheit = (celsius * 9.0 / 5.0) + 32.0
            out_lines.append(f"Temperature in Celsius: {celsius:.2f}")
            out_lines.append(f"Temperature in Fahrenheit: {fahrenheit:.2f}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

